{
  const upperIndex = sampleData.findIndex(row => row.k >= TEMP_MAX_K)
  if (upperIndex > 0 && sampleData[upperIndex].k > TEMP_MAX_K) {
    const a = sampleData[upperIndex - 1]
    const b = sampleData[upperIndex]
    const t = (TEMP_MAX_K - a.k) / (b.k - a.k)
    sampleData = sampleData.slice(0, upperIndex).concat([{
      k: TEMP_MAX_K,
      t: TEMP_MAX_K - 273.15,
      atm: lerp(a.atm, b.atm, t),
      mmHg: lerp(a.mmHg, b.mmHg, t),
      rhoL: lerp(a.rhoL, b.rhoL, t),
      muL: lerp(a.muL, b.muL, t),
      kL: lerp(a.kL, b.kL, t),
      sigma: lerp(a.sigma, b.sigma, t)
    }])
  } else {
    sampleData = sampleData.filter(row => row.k <= TEMP_MAX_K)
  }
}

