function mmHgToAtm(v) {
  return v / 760
}

function atmToMmHg(v) {
  return v * 760
}

function clamp(v, a, b) {
  return Math.max(a, Math.min(b, v))
}

function lerp(a, b, t) {
  return a + (b - a) * t
}

function lerpAngle(a, b, t) {
  const tau = Math.PI * 2
  let delta = (b - a) % tau
  if (delta > Math.PI) delta -= tau
  if (delta < -Math.PI) delta += tau
  return a + delta * t
}

function mixPoint(a, b, t) {
  return { x: lerp(a.x, b.x, t), y: lerp(a.y, b.y, t) }
}

function smoothstep(a, b, x) {
  const t = clamp((x - a) / (b - a), 0, 1)
  return t * t * (3 - 2 * t)
}

function easeInOut(t) {
  return t < 0.5 ? 4 * t * t * t : 1 - Math.pow(-2 * t + 2, 3) / 2
}

function formatNumber(v, digits = 1) {
  return v.toFixed(digits).replace('.', ',')
}

function formatTemp(temp) {
  return `${formatNumber(temp, 2)} °C`
}

function formatKelvin(k) {
  return `${formatNumber(k, 2)} K`
}

function formatCelsiusFromK(k) {
  return `${formatNumber(k - 273.15, 2)} °C`
}

function formatTempPairK(k) {
  return `${formatKelvin(k)} · ${formatCelsiusFromK(k)}`
}

function formatPressureMmHg(v) {
  const digits = v < 10 ? 3 : v < 100 ? 2 : 1
  return `${formatNumber(v, digits)} mmHg`
}

function formatPressureAtm(v) {
  const digits = v < 0.1 ? 4 : v < 1 ? 3 : 2
  return `${formatNumber(v, digits)} atm`
}

function pressureFactor(mmHg) {
  const min = Math.max(sampleData[0].mmHg, 1e-6)
  const max = Math.max(sampleData[sampleData.length - 1].mmHg, min * 1.000001)
  const safe = clamp(mmHg, min, max)
  return clamp((Math.log(safe) - Math.log(min)) / Math.max(Math.log(max) - Math.log(min), 1e-6), 0, 1)
}

function tempToColor(tempK) {
  const t = clamp((tempK - TEMP_MIN_K) / Math.max(TEMP_MAX_K - TEMP_MIN_K, 1), 0, 1)
  const r = Math.round(lerp(80, 255, t))
  const g = Math.round(lerp(190, 110, t))
  const b = Math.round(lerp(255, 72, t))
  return `rgb(${r},${g},${b})`
}

function mmHgToSliderValue(p) {
  return p
}

function sliderValueToMmHg(v) {
  return v
}

function findNearestSampleIndex(p) {
  let best = 0
  let minDiff = Infinity
  sampleData.forEach((row, i) => {
    const diff = Math.abs(row.mmHg - p)
    if (diff < minDiff) {
      minDiff = diff
      best = i
    }
  })
  return best
}

function interpolateBoilingTemp(mmHg) {
  return interpolateSaturationRow(mmHg).t
}

function interpolateSaturationRow(mmHg) {
  if (mmHg <= sampleData[0].mmHg) return { ...sampleData[0] }
  if (mmHg >= sampleData[sampleData.length - 1].mmHg) return { ...sampleData[sampleData.length - 1] }
  const logP = Math.log(mmHg)
  for (let i = 0; i < sampleData.length - 1; i++) {
    const a = sampleData[i]
    const b = sampleData[i + 1]
    if (mmHg >= a.mmHg && mmHg <= b.mmHg) {
      const t = (logP - Math.log(a.mmHg)) / (Math.log(b.mmHg) - Math.log(a.mmHg))
      return {
        k: lerp(a.k, b.k, t),
        t: lerp(a.t, b.t, t),
        atm: lerp(a.atm, b.atm, t),
        mmHg,
        rhoL: lerp(a.rhoL, b.rhoL, t),
        muL: lerp(a.muL, b.muL, t),
        kL: lerp(a.kL, b.kL, t),
        sigma: lerp(a.sigma, b.sigma, t)
      }
    }
  }
  return { ...sampleData[Math.max(0, sampleData.length - 1)] }
}

function phaseLevels(tempK) {
  const meltWindow = 3.2
  const melt = tempK <= MELT_K ? 0 : smoothstep(MELT_K - 0.2, MELT_K + meltWindow, tempK)
  const pressureAtm = mmHgToAtm(state.pressureMmHg)
  const pressureBoost = clamp(Math.log10(Math.max(pressureAtm, TRIPLE_ATM)) - Math.log10(TRIPLE_ATM), 0, 4.6)
  const boilWindow = clamp(18 + pressureBoost * 4.8 + (state.actualBoil - 373.15) * 0.045, 16, 46)
  const boilStart = state.actualBoil - boilWindow * 1.08
  const boilEnd = state.actualBoil + boilWindow * 1.52
  const boil = smoothstep(boilStart, boilEnd, tempK)
  const liquidEnvelope = 1 - smoothstep(state.actualBoil - boilWindow * 0.24, state.actualBoil + boilWindow * 1.06, tempK)
  const solid = clamp(1 - melt, 0, 1)
  const liquid = clamp(melt * Math.pow(liquidEnvelope, 0.92) * (1.04 - boil * 0.08), 0, 1)
  const vapor = clamp(boil, 0, 1)
  return { melt, boil, solid, liquid, vapor, boilWindow, boilStart, boilEnd }
}

function resizeCanvas(target, context, heightCSS) {
  const rect = target.getBoundingClientRect()
  target.width = Math.floor(rect.width * DPR)
  target.height = Math.floor(heightCSS * DPR)
  context.setTransform(DPR, 0, 0, DPR, 0, 0)
}

function resize() {
  const rect = canvas.getBoundingClientRect()
  canvas.width = Math.floor(rect.width * DPR)
  canvas.height = Math.floor(rect.height * DPR)
  ctx.setTransform(DPR, 0, 0, DPR, 0, 0)
  config.width = rect.width
  config.height = rect.height
  config.scale = Math.min(config.width / 1180, config.height / 820)
  config.panelCenters = [config.width * 0.24, config.width * 0.50, config.width * 0.76]
  config.clusterY = config.height * 0.42
  config.descriptionY = config.height * 0.86
  config.thermoLeftX = 50 * config.scale + 14
  config.thermoRightX = config.width - 50 * config.scale - 14
  config.thermoTop = 126 * config.scale
  config.thermoBottom = config.height * 0.81
  config.phaseBoxY = config.height * 0.09

  if (phaseChart && pctx) {
    const phaseRect = phaseChart.getBoundingClientRect()
    phaseChart.width = Math.floor(phaseRect.width * DPR)
    phaseChart.height = Math.floor(phaseRect.height * DPR)
    pctx.setTransform(DPR, 0, 0, DPR, 0, 0)
    diagramConfig.width = phaseRect.width
    diagramConfig.height = phaseRect.height
    diagramConfig.scale = Math.min(diagramConfig.width / 720, diagramConfig.height / 340)
  }
}

function pointFromOffset(centerX, centerY, offset) {
  return {
    x: centerX + offset[0] * config.scale,
    y: centerY + offset[1] * config.scale
  }
}

function clampPointToRect(point, rect, padding) {
  return {
    x: clamp(point.x, rect.x + padding, rect.x + rect.w - padding),
    y: clamp(point.y, rect.y + padding, rect.y + rect.h - padding)
  }
}

function isTripleTutorialStep() {
  const step = tutorialSteps[state.tutorialStep] || tutorialSteps[0]
  return !!(step && step.diagramFocus === 'triple')
}

function isNearTriplePoint() {
  const tempClose = Math.abs(state.temp - TRIPLE_K) <= 1.2
  const pressureAtm = mmHgToAtm(state.pressureMmHg)
  const pressureClose = Math.abs(Math.log10(Math.max(pressureAtm, 1e-6)) - Math.log10(TRIPLE_ATM)) <= 0.09
  return tempClose && pressureClose
}

function shouldShowTripleEquilibrium() {
  return state.forceTripleView || isTripleTutorialStep() || isNearTriplePoint()
}

function isNearCriticalPoint() {
  const tempClose = Math.abs(state.temp - CRITICAL_K) <= 4
  const pressureAtm = mmHgToAtm(state.pressureMmHg)
  const pressureClose = Math.abs(Math.log10(Math.max(pressureAtm, 1e-6)) - Math.log10(CRITICAL_ATM)) <= 0.035
  return tempClose && pressureClose
}

function shouldShowCriticalComparison() {
  return state.forceCriticalView || isNearCriticalPoint()
}

function tripleStateGroup(index) {
  const groups = [0, 0, 1, 1, 2, 2]
  return groups[index % groups.length]
}

function vaporTransitionMix(boilT) {
  return smoothstep(0.10, 0.92, boilT)
}

function vaporMotionPoint(index, molecule, vaporBox, vaporPadding, time, dt, levels, thermalDrive, lowPressureBoost, pressureTightening, liquidPoint, boilT) {
  const anchor = vaporAnchors[index % vaporAnchors.length]
  const left = vaporBox.x + vaporPadding
  const right = vaporBox.x + vaporBox.w - vaporPadding
  const top = vaporBox.y + vaporPadding
  const bottom = vaporBox.y + vaporBox.h - vaporPadding
  const innerW = Math.max(20 * config.scale, right - left)
  const innerH = Math.max(20 * config.scale, bottom - top)
  const centerX = (left + right) / 2
  const centerY = (top + bottom) / 2
  const transitionMix = vaporTransitionMix(boilT)

  const roamX = innerW * clamp(0.44 + levels.vapor * 0.18 + thermalDrive * 0.30 + lowPressureBoost * 0.18 - pressureTightening * 0.20, 0.30, 0.94)
  const roamY = innerH * clamp(0.46 + levels.vapor * 0.18 + thermalDrive * 0.28 + lowPressureBoost * 0.16 - pressureTightening * 0.18, 0.32, 0.96)
  const targetX = centerX + (anchor[0] - 0.5) * roamX
  const targetY = centerY + (anchor[1] - 0.5) * roamY
  const bridgeTargetX = lerp(liquidPoint.x, targetX, transitionMix)
  const bridgeTargetY = lerp(liquidPoint.y, targetY, transitionMix)

  if (!Number.isFinite(molecule.vaporX) || !Number.isFinite(molecule.vaporY)) {
    molecule.vaporX = lerp(liquidPoint.x, bridgeTargetX, 0.10)
    molecule.vaporY = lerp(liquidPoint.y, bridgeTargetY, 0.10)
    molecule.vaporVX = 0
    molecule.vaporVY = 0
    molecule.vaporTurn = molecule.phase + index * 0.7
  }

  const maxSpeed = (18 + levels.vapor * 34 + thermalDrive * 54 + lowPressureBoost * 10 - pressureTightening * 8) * (0.42 + transitionMix * 0.58) * config.scale
  const accel = (42 + levels.vapor * 42 + thermalDrive * 72 + lowPressureBoost * 10 - pressureTightening * 8) * (0.32 + transitionMix * 0.68) * config.scale
  const spring = 1.35 + pressureTightening * 0.82 - lowPressureBoost * 0.14
  const damping = clamp(0.935 - thermalDrive * 0.06 + pressureTightening * 0.025, 0.86, 0.96)

  const turnWave =
    Math.sin(time * (0.75 + (molecule.seed % 1) * 0.55) + molecule.phase) * 0.95 +
    Math.sin(time * (1.18 + ((molecule.seed * 1.71) % 1) * 0.42) + molecule.phase * 0.63) * 0.42

  molecule.vaporTurn += turnWave * dt * (0.55 + transitionMix * 1.45 + thermalDrive * 1.2 + lowPressureBoost * 0.10)

  let ax = Math.cos(molecule.vaporTurn) * accel * transitionMix + (bridgeTargetX - molecule.vaporX) * spring
  let ay = Math.sin(molecule.vaporTurn) * accel * transitionMix + (bridgeTargetY - molecule.vaporY) * spring

  const edgeX = Math.min(molecule.vaporX - left, right - molecule.vaporX)
  const edgeY = Math.min(molecule.vaporY - top, bottom - molecule.vaporY)
  if (edgeX < 54 * config.scale) ax += (centerX - molecule.vaporX) * (1.2 + pressureTightening * 0.5)
  if (edgeY < 54 * config.scale) ay += (centerY - molecule.vaporY) * (1.2 + pressureTightening * 0.5)

  if (transitionMix < 0.999) {
    ax += (liquidPoint.x - molecule.vaporX) * (1 - transitionMix) * 3.4
    ay += (liquidPoint.y - molecule.vaporY) * (1 - transitionMix) * 3.4
  }

  molecule.vaporVX = (molecule.vaporVX + ax * dt) * damping
  molecule.vaporVY = (molecule.vaporVY + ay * dt) * damping

  const speed = Math.hypot(molecule.vaporVX, molecule.vaporVY)
  if (speed > maxSpeed) {
    const s = maxSpeed / speed
    molecule.vaporVX *= s
    molecule.vaporVY *= s
  }

  molecule.vaporX += molecule.vaporVX * dt
  molecule.vaporY += molecule.vaporVY * dt

  if (molecule.vaporX < left) {
    molecule.vaporX = left
    molecule.vaporVX = Math.abs(molecule.vaporVX) * 0.72
  } else if (molecule.vaporX > right) {
    molecule.vaporX = right
    molecule.vaporVX = -Math.abs(molecule.vaporVX) * 0.72
  }

  if (molecule.vaporY < top) {
    molecule.vaporY = top
    molecule.vaporVY = Math.abs(molecule.vaporVY) * 0.72
  } else if (molecule.vaporY > bottom) {
    molecule.vaporY = bottom
    molecule.vaporVY = -Math.abs(molecule.vaporVY) * 0.72
  }

  return { x: molecule.vaporX, y: molecule.vaporY }
}

function relaxVaporPositions(points, rect, padding, boilT, levels, thermalDrive, lowPressureBoost, pressureTightening) {
  const mix = clamp(boilT * (0.34 + levels.vapor * 0.38), 0, 0.74)
  if (mix <= 0.001) return points
  const minDist = clamp(78 + thermalDrive * 20 + levels.vapor * 18 + lowPressureBoost * 14 - pressureTightening * 10, 70, 110) * config.scale
  const left = rect.x + padding
  const right = rect.x + rect.w - padding
  const top = rect.y + padding
  const bottom = rect.y + rect.h - padding

  for (let iter = 0; iter < 8; iter++) {
    for (let i = 0; i < points.length; i++) {
      for (let j = i + 1; j < points.length; j++) {
        const a = points[i]
        const b = points[j]
        let dx = b.x - a.x
        let dy = b.y - a.y
        let dist = Math.hypot(dx, dy)
        if (dist < 0.001) {
          const angle = (i * 1.7 + j * 2.3 + iter * 0.9)
          dx = Math.cos(angle)
          dy = Math.sin(angle)
          dist = 1
        }
        if (dist >= minDist) continue
        const overlap = (minDist - dist) * 0.5 * (0.22 + mix * 0.22)
        const nx = dx / dist
        const ny = dy / dist
        a.x -= nx * overlap
        a.y -= ny * overlap
        b.x += nx * overlap
        b.y += ny * overlap
      }
    }

    for (const p of points) {
      p.x = clamp(p.x, left, right)
      p.y = clamp(p.y, top, bottom)
    }
  }

  return points
}

function relaxLiquidPositions(points, rect, padding, levels, thermalDrive, pressureTightening, boilT) {
  const mix = clamp(levels.liquid * (1 - boilT) * 1.3, 0, 0.92)
  if (mix <= 0.001) return points
  const minDist = clamp(84 + thermalDrive * 12 - pressureTightening * 6, 76, 100) * config.scale
  const left = rect.x + padding
  const right = rect.x + rect.w - padding
  const top = rect.y + padding
  const bottom = rect.y + rect.h - padding
  const centerX = (left + right) * 0.5
  const centerY = (top + bottom) * 0.5 + 6 * config.scale

  for (let iter = 0; iter < 6; iter++) {
    for (let i = 0; i < points.length; i++) {
      const a = points[i]
      for (let j = i + 1; j < points.length; j++) {
        const b = points[j]
        let dx = b.x - a.x
        let dy = b.y - a.y
        let dist = Math.hypot(dx, dy)
        if (dist < 0.001) {
          const angle = (i * 1.4 + j * 1.9 + iter * 0.8)
          dx = Math.cos(angle)
          dy = Math.sin(angle)
          dist = 1
        }
        if (dist >= minDist) continue
        const overlap = (minDist - dist) * 0.5 * (0.18 + mix * 0.18)
        const nx = dx / dist
        const ny = dy / dist
        a.x -= nx * overlap
        a.y -= ny * overlap
        b.x += nx * overlap
        b.y += ny * overlap
      }
      a.x = lerp(a.x, centerX, 0.01 + mix * 0.03)
      a.y = lerp(a.y, centerY, 0.01 + mix * 0.03)
      a.x = clamp(a.x, left, right)
      a.y = clamp(a.y, top, bottom)
    }
  }

  return points
}


function computeMolecules(tempK, time) {
  const criticalStep = shouldShowCriticalComparison()
  const tripleStep = shouldShowTripleEquilibrium()
  let levels = phaseLevels(tempK)
  if (criticalStep) {
    levels = { melt: 0.55, boil: 0.52, solid: 0.33, liquid: 0.33, vapor: 0.34 }
  } else if (tripleStep) {
    levels = { melt: 0.52, boil: 0.48, solid: 0.34, liquid: 0.33, vapor: 0.33 }
  }
  const meltT = easeInOut(tripleStep ? 0.52 : levels.melt)
  const boilT = easeInOut(tripleStep ? 0.48 : levels.boil)
  const dt = clamp(state.dt || 1 / 60, 1 / 240, 0.04)
  const tempNorm = clamp((tempK - TEMP_MIN_K) / Math.max(TEMP_MAX_K - TEMP_MIN_K, 1), 0, 1)
  const thermalDrive = Math.pow(tempNorm, 1.18)
  const pNorm = pressureFactor(state.pressureMmHg)
  const pressureTightening = Math.pow(pNorm, 0.82)
  const lowPressureBoost = 1 - pNorm

  const spreadSolid = clamp(0.84 + thermalDrive * 0.16 - pressureTightening * 0.08, 0.72, 1.08)
  const spreadLiquid = clamp(0.88 + thermalDrive * 0.24 + levels.boil * 0.05 - pressureTightening * 0.12 + lowPressureBoost * 0.03, 0.82, 1.14)
  const liquidBox = panelRect(1)
  const liquidPadding = 36 * config.scale
  const vaporBox = panelRect(2)
  const vaporPadding = 28 * config.scale
  const boilMixes = new Array(molecules.length).fill(boilT)

  const prePositions = molecules.map((m, i) => {
    const solid = pointFromOffset(config.panelCenters[0], config.clusterY, [solidOffsets[i][0] * spreadSolid, solidOffsets[i][1] * spreadSolid])
    const liquid = pointFromOffset(config.panelCenters[1], config.clusterY, [liquidOffsets[i][0] * spreadLiquid, liquidOffsets[i][1] * spreadLiquid])
    const intoLiquid = mixPoint(solid, liquid, meltT)
    const staggerSeed = molecules.length > 1 ? i / (molecules.length - 1) : 0.5
    const stagger = (staggerSeed - 0.5) * 0.46 + Math.sin((m.seed % 1) * 9.7 + i * 0.37) * 0.035
    const localBoil = tripleStep || criticalStep ? boilT : clamp(levels.boil - stagger, 0, 1)
    const localBoilT = easeInOut(localBoil)
    const boilBridge = vaporTransitionMix(localBoilT)
    boilMixes[i] = boilBridge
    const liquidDamping = 1 - boilBridge * 0.86
    const liquidVibration = (0.50 + 1.25 * levels.liquid + thermalDrive * 2.25 - pressureTightening * 0.28) * config.scale
    const liquidSpeed = 0.54 + levels.liquid * 0.46 + thermalDrive * 0.52 + lowPressureBoost * 0.06
    const driftX = Math.sin(time * (1.8 + (m.seed % 1) * 2.1) * liquidSpeed + m.phase) * liquidVibration * liquidDamping
    const driftY = Math.cos(time * (1.4 + ((m.seed * 1.71) % 1) * 1.8) * liquidSpeed + m.phase * 0.7) * liquidVibration * (0.88 + thermalDrive * 0.14) * liquidDamping
    const liquidPoint = { x: intoLiquid.x + driftX, y: intoLiquid.y + driftY }
    const vapor = vaporMotionPoint(i, m, vaporBox, vaporPadding, time, dt, levels, thermalDrive, lowPressureBoost, pressureTightening, liquidPoint, boilBridge)

    if (tripleStep) {
      const solidJitter = (1.8 + (m.seed % 1) * 1.4) * config.scale
      const solidPoint = {
        x: solid.x + Math.sin(time * (1.3 + (m.seed % 1) * 0.35) + m.phase) * solidJitter,
        y: solid.y + Math.cos(time * (1.1 + (m.seed % 1) * 0.28) + m.phase * 0.8) * solidJitter
      }
      const calmLiquidPoint = {
        x: liquid.x + Math.sin(time * (1.7 + (m.seed % 1) * 0.42) + m.phase) * 6.5 * config.scale,
        y: liquid.y + Math.cos(time * (1.4 + ((m.seed * 1.41) % 1) * 0.38) + m.phase * 0.7) * 5.5 * config.scale
      }
      const group = tripleStateGroup(i)
      if (group === 0) return solidPoint
      if (group === 1) return calmLiquidPoint
      return vapor
    }

    return mixPoint(liquidPoint, vapor, boilBridge)
  })

  if (!tripleStep) {

    relaxLiquidPositions(prePositions, liquidBox, liquidPadding, levels, thermalDrive, pressureTightening, boilT)
    relaxVaporPositions(prePositions, vaporBox, vaporPadding, boilT, levels, thermalDrive, lowPressureBoost, pressureTightening)
  }

  molecules.forEach((m, i) => {
    const localBoilT = boilMixes[i] ?? boilT
    const current = !tripleStep && levels.liquid > 0.22 && levels.liquid >= levels.solid * 0.55 && localBoilT < 0.86
      ? clampPointToRect(prePositions[i], liquidBox, liquidPadding)
      : prePositions[i]
    let vx = 0
    let vy = 0
    for (let j = 0; j < prePositions.length; j++) {
      if (i === j) continue
      const other = prePositions[j]
      const dx = other.x - current.x
      const dy = other.y - current.y
      const dist = Math.hypot(dx, dy) || 1
      const reach = clamp((220 - levels.vapor * 138 - thermalDrive * 56 + pressureTightening * 54), 58, 234) * config.scale
      const w = clamp(1 - dist / reach, 0, 1)
      vx += dx / dist * w
      vy += dy / dist * w
    }

    if (levels.vapor > 0.01) {
      m.vaporX = lerp(m.vaporX, current.x, 0.18 + levels.vapor * 0.10)
      m.vaporY = lerp(m.vaporY, current.y, 0.18 + levels.vapor * 0.10)
    }

    const attraction = Math.hypot(vx, vy)
    const structureAngle = lerpAngle(
      lerpAngle(solidAngles[i % solidAngles.length], liquidAngles[i % liquidAngles.length], meltT),
      vaporAngles[i % vaporAngles.length],
      localBoilT
    )
    const attractionAngle = attraction > 0.02 ? Math.atan2(vy, vx) : structureAngle
    const desired = lerpAngle(structureAngle, attractionAngle, clamp(levels.liquid * 0.42 + levels.vapor * 0.28, 0, 0.54))
    const velocityAngle = Math.hypot(m.vaporVX, m.vaporVY) > 0.1 ? Math.atan2(m.vaporVY, m.vaporVX) : desired
    const freeTilt =
      Math.sin(time * (0.92 + (m.seed % 1) * 0.58) + m.phase) * (0.16 + levels.vapor * 0.16) +
      Math.cos(time * (1.36 + ((m.seed * 1.43) % 1) * 0.42) + m.phase * 0.7) * (0.08 + levels.vapor * 0.08)
    const vaporAngle = lerpAngle(desired, velocityAngle, 0.68) + freeTilt
    const wobble = Math.sin(time * (1.7 + (m.seed % 1) * 0.8 + tempNorm * 0.9) + m.phase) * (0.04 + levels.liquid * 0.10 + levels.vapor * 0.10)
    m.angle = lerpAngle(desired, vaporAngle, localBoilT) + wobble

    const hr = 26 * config.scale
    const half = 0.91
    m.pos.x = current.x
    m.pos.y = current.y
    m.h1.x = current.x + Math.cos(m.angle - half) * hr
    m.h1.y = current.y + Math.sin(m.angle - half) * hr
    m.h2.x = current.x + Math.cos(m.angle + half) * hr
    m.h2.y = current.y + Math.sin(m.angle + half) * hr
  })
  return levels
}

function spawnBreak(x, y, intensity) {
  const count = Math.round(4 + intensity * 6)
  for (let i = 0; i < count; i++) {
    const a = Math.random() * Math.PI * 2
    const s = (1.3 + Math.random() * 2.3 + intensity * 2.2) * config.scale
    particles.push({
      x,
      y,
      vx: Math.cos(a) * s,
      vy: Math.sin(a) * s - Math.random() * 1.2,
      life: 0,
      max: 28 + Math.random() * 22,
      r: (1.5 + Math.random() * 2.5) * config.scale
    })
  }
}

function updateParticles() {
  for (let i = particles.length - 1; i >= 0; i--) {
    const p = particles[i]
    p.life += 1
    p.x += p.vx
    p.y += p.vy
    p.vy += 0.02 * config.scale
    p.vx *= 0.985
    if (p.life >= p.max) particles.splice(i, 1)
  }
}

function drawParticles() {
  for (const p of particles) {
    const t = 1 - p.life / p.max
    ctx.globalAlpha = t * 0.85
    ctx.fillStyle = 'rgba(255,168,92,1)'
    ctx.beginPath()
    ctx.arc(p.x, p.y, p.r * t, 0, Math.PI * 2)
    ctx.fill()
  }
  ctx.globalAlpha = 1
}

function drawRoundedRect(x, y, w, h, r) {
  const rr = Math.max(0, Math.min(r, w / 2, h / 2))
  ctx.beginPath()
  ctx.moveTo(x + rr, y)
  ctx.arcTo(x + w, y, x + w, y + h, rr)
  ctx.arcTo(x + w, y + h, x, y + h, rr)
  ctx.arcTo(x, y + h, x, y, rr)
  ctx.arcTo(x, y, x + w, y, rr)
  ctx.closePath()
}

function drawRoundedRectOn(targetCtx, x, y, w, h, r) {
  const rr = Math.max(0, Math.min(r, w / 2, h / 2))
  targetCtx.beginPath()
  targetCtx.moveTo(x + rr, y)
  targetCtx.arcTo(x + w, y, x + w, y + h, rr)
  targetCtx.arcTo(x + w, y + h, x, y + h, rr)
  targetCtx.arcTo(x, y + h, x, y, rr)
  targetCtx.arcTo(x, y, x + w, y, rr)
  targetCtx.closePath()
}

function panelRect(index) {
  const w = 305 * config.scale
  const h = 430 * config.scale
  return { x: config.panelCenters[index] - w / 2, y: config.phaseBoxY, w, h }
}

function drawBackground(levels, temp) {
  const criticalView = shouldShowCriticalComparison()
  const grad = ctx.createLinearGradient(0, 0, 0, config.height)
  grad.addColorStop(0, criticalView ? '#f4f7fb' : '#f7fbff')
  grad.addColorStop(1, criticalView ? '#e7edf5' : '#eef3f7')
  ctx.fillStyle = grad
  ctx.fillRect(0, 0, config.width, config.height)

  const heatAlpha = clamp((temp - TEMP_MIN_K) / Math.max(TEMP_MAX_K - TEMP_MIN_K, 1), 0, 1)
  const warm = ctx.createRadialGradient(config.width * 0.5, config.height * 1.08, 24, config.width * 0.5, config.height * 1.08, config.width * 0.42)
  warm.addColorStop(0, `rgba(255,142,76,${0.22 + heatAlpha * 0.18})`)
  warm.addColorStop(0.5, `rgba(255,174,96,${0.08 + heatAlpha * 0.08})`)
  warm.addColorStop(1, 'rgba(255,174,96,0)')
  ctx.fillStyle = warm
  ctx.fillRect(0, 0, config.width, config.height)

  if (criticalView) {
    const boxW = Math.min(config.width - 165 * config.scale, 1040 * config.scale)
    const boxH = 510 * config.scale
    const boxX = config.width * 0.5 - boxW * 0.5
    const boxY = Math.max(24 * config.scale, config.phaseBoxY - 6 * config.scale)
    const glow = ctx.createLinearGradient(boxX, boxY, boxX, boxY + boxH)
    glow.addColorStop(0, 'rgba(255,255,255,0.82)')
    glow.addColorStop(1, 'rgba(244,248,252,0.96)')
    drawRoundedRect(boxX, boxY, boxW, boxH, 26 * config.scale)
    ctx.fillStyle = glow
    ctx.fill()
    ctx.lineWidth = 2.4 * config.scale
    ctx.strokeStyle = 'rgba(134,108,255,0.26)'
    ctx.stroke()

    const haze = ctx.createRadialGradient(config.width * 0.5, config.clusterY + 20 * config.scale, 20, config.width * 0.5, config.clusterY + 20 * config.scale, 290 * config.scale)
    haze.addColorStop(0, 'rgba(137,205,255,0.26)')
    haze.addColorStop(0.46, 'rgba(165,154,255,0.16)')
    haze.addColorStop(1, 'rgba(165,154,255,0)')
    ctx.fillStyle = haze
    ctx.fillRect(0, 0, config.width, config.height)
    return
  }

  for (let i = 0; i < 3; i++) {
    const box = panelRect(i)
    if (i === 0) { box.x += 10 * config.scale }
    if (i === 2) { box.x -= 10 * config.scale }
    const active = i === 0 ? levels.solid : i === 1 ? levels.liquid : levels.vapor
    const glow = ctx.createLinearGradient(box.x, box.y, box.x, box.y + box.h)
    glow.addColorStop(0, `rgba(255,255,255,${0.78 + active * 0.08})`)
    glow.addColorStop(1, `rgba(245,249,252,${0.94})`)
    drawRoundedRect(box.x, box.y, box.w, box.h, 22 * config.scale)
    ctx.fillStyle = glow
    ctx.fill()
    ctx.lineWidth = (1.5 + active * 1.1) * config.scale
    ctx.strokeStyle = i === 0 ? `rgba(109,199,255,${0.24 + active * 0.25})` : i === 1 ? `rgba(92,194,255,${0.2 + active * 0.3})` : `rgba(255,144,88,${0.18 + active * 0.32})`
    ctx.stroke()
  }

  ctx.strokeStyle = 'rgba(52,86,112,0.12)'
  ctx.lineWidth = 1 * config.scale
  ctx.setLineDash([4 * config.scale, 9 * config.scale])
  ctx.beginPath()
  ctx.moveTo(config.width * 0.365, config.phaseBoxY)
  ctx.lineTo(config.width * 0.365, config.phaseBoxY + 430 * config.scale)
  ctx.moveTo(config.width * 0.635, config.phaseBoxY)
  ctx.lineTo(config.width * 0.635, config.phaseBoxY + 430 * config.scale)
  ctx.stroke()
  ctx.setLineDash([])
}

function drawTitles(levels) {
  if (shouldShowCriticalComparison()) {
    const x = config.width * 0.5
    const y = config.phaseBoxY + 32 * config.scale
    ctx.save()
    ctx.textAlign = 'center'
    ctx.fillStyle = '#6657d6'
    ctx.globalAlpha = 0.98
    ctx.font = `${Math.round(26 * config.scale)}px Inter, sans-serif`
    ctx.fillText('Supercrítico', x, y)
    ctx.font = `${Math.round(12 * config.scale)}px Inter, sans-serif`
    ctx.fillStyle = 'rgba(79,84,122,0.82)'
    ctx.fillText('mistura contínua entre características de líquido e gás', x, y + 18 * config.scale)
    ctx.restore()
    return
  }

  const labels = [
    { title: 'Gelo', sub: 'rede mais organizada', level: levels.solid, color: '#2e6f96' },
    { title: 'Água', sub: 'pontes de H temporárias', level: levels.liquid, color: '#2a6f90' },
    { title: 'Vapor', sub: 'moléculas mais afastadas', level: levels.vapor, color: '#aa663e' }
  ]
  labels.forEach((item, i) => {
    const x = config.panelCenters[i]
    const y = config.phaseBoxY + 30 * config.scale
    ctx.textAlign = 'center'
    ctx.fillStyle = item.color
    ctx.globalAlpha = 0.62 + item.level * 0.38
    ctx.font = `${Math.round(24 * config.scale)}px Inter, sans-serif`
    ctx.fillText(item.title, x, y)
    ctx.font = `${Math.round(12 * config.scale)}px Inter, sans-serif`
    ctx.fillStyle = 'rgba(54,89,110,0.68)'
    ctx.fillText(item.sub, x, y + 16 * config.scale)
    ctx.globalAlpha = 1
  })
}

function drawViewerThermometer({ x, value, min, max, label, valueLabel, marks = [], accent = '#d81f2d', side = 'right', scaleFn = null }) {
  const y1 = config.thermoTop
  const y2 = config.thermoBottom
  const tubeW = 24 * config.scale
  const bulbR = 26 * config.scale
  const hitPad = 28 * config.scale
  const normalize = typeof scaleFn === 'function'
    ? v => clamp(scaleFn(v, min, max), 0, 1)
    : v => clamp((v - min) / Math.max(max - min, 1), 0, 1)
  const fill = normalize(value)
  const fillY = lerp(y2, y1, fill)
  const markerDir = side === 'left' ? -1 : 1
  const lineStart = x + markerDir * 16 * config.scale
  const lineEnd = x + markerDir * 32 * config.scale
  const textX = x + markerDir * 38 * config.scale
  const titleY = y1 - 24 * config.scale
  const valueY = y1 - 48 * config.scale

  ctx.save()
  ctx.textAlign = 'center'
  ctx.fillStyle = '#1d364d'
  ctx.font = `${Math.round(14 * config.scale)}px Inter, sans-serif`
  ctx.fillText(label, x, titleY)
  ctx.font = `${Math.round(20 * config.scale)}px Inter, sans-serif`
  ctx.fillText(valueLabel, x, valueY)

  ctx.beginPath()
  ctx.roundRect(x - tubeW / 2, y1, tubeW, y2 - y1, tubeW / 2)
  ctx.fillStyle = 'rgba(255,255,255,0.55)'
  ctx.fill()
  ctx.lineWidth = 2 * config.scale
  ctx.strokeStyle = 'rgba(35,62,82,0.18)'
  ctx.stroke()

  const innerW = 12 * config.scale
  ctx.beginPath()
  ctx.roundRect(x - innerW / 2, fillY, innerW, y2 - fillY, innerW / 2)
  const fg = ctx.createLinearGradient(0, y1, 0, y2)
  fg.addColorStop(0, '#ff7d76')
  fg.addColorStop(0.45, accent)
  fg.addColorStop(1, '#970014')
  ctx.fillStyle = fg
  ctx.fill()

  ctx.beginPath()
  ctx.arc(x, y2 + bulbR * 0.06, bulbR, 0, Math.PI * 2)
  const bg = ctx.createRadialGradient(x - 6 * config.scale, y2 - 4 * config.scale, 2, x, y2, bulbR)
  bg.addColorStop(0, '#ffe3d4')
  bg.addColorStop(0.16, accent)
  bg.addColorStop(1, '#8a0013')
  ctx.fillStyle = bg
  ctx.fill()
  ctx.lineWidth = 2 * config.scale
  ctx.strokeStyle = 'rgba(35,62,82,0.18)'
  ctx.stroke()

  ctx.textAlign = side === 'left' ? 'right' : 'left'
  ctx.font = `${Math.round(12 * config.scale)}px Inter, sans-serif`
  marks.forEach(mark => {
    const p = normalize(mark.value)
    const y = lerp(y2, y1, p)
    ctx.strokeStyle = 'rgba(40,70,92,0.32)'
    ctx.lineWidth = 1.5 * config.scale
    ctx.beginPath()
    ctx.moveTo(lineStart, y)
    ctx.lineTo(lineEnd, y)
    ctx.stroke()
    ctx.fillStyle = mark.highlight ? 'rgba(219,81,66,0.95)' : 'rgba(29,54,77,0.72)'
    ctx.fillText(mark.label, textX, y + 4 * config.scale)
  })
  const bounds = {
    x: x - Math.max(tubeW * 2, bulbR + hitPad),
    y: y1 - 58 * config.scale,
    w: Math.max(tubeW * 4, (bulbR + hitPad) * 2),
    h: (y2 - y1) + bulbR * 2 + 86 * config.scale
  }
  if (label === 'Temperatura') config.tempThermoBounds = bounds
  if (label === 'Pressão') config.pressureThermoBounds = bounds
  ctx.restore()
}


function pressureThermoScale(value, min, max) {
  const safeMin = Math.max(min, 0.000001)
  const safeValue = Math.max(value, safeMin)
  return (Math.log10(safeValue) - Math.log10(safeMin)) / Math.max(Math.log10(max) - Math.log10(safeMin), 0.000001)
}

function drawTemperatureThermometer(temp) {
  const marks = [
    { value: TEMP_MIN_K, label: '0,00 K' },
    { value: MELT_K, label: '273,15 K', highlight: true },
    { value: state.actualBoil, label: formatKelvin(state.actualBoil), highlight: true },
    { value: TEMP_MAX_K, label: formatKelvin(TEMP_MAX_K) }
  ]
  drawViewerThermometer({
    x: config.thermoLeftX,
    value: temp,
    min: TEMP_MIN_K,
    max: TEMP_MAX_K,
    label: 'Temperatura',
    valueLabel: formatKelvin(temp),
    marks,
    accent: '#e23636',
    side: 'right'
  })
}

function drawPressureThermometer(mmHg) {
  const pressureAtm = mmHgToAtm(mmHg)
  const marks = [
    { value: sampleData[0].atm, label: formatPressureAtm(sampleData[0].atm) },
    { value: 0.01, label: '0,010 atm' },
    { value: 0.1, label: '0,100 atm' },
    { value: 1, label: '1,000 atm', highlight: true },
    { value: 10, label: '10,000 atm' },
    { value: sampleData[sampleData.length - 1].atm, label: formatPressureAtm(sampleData[sampleData.length - 1].atm) }
  ].filter(mark => mark.value >= sampleData[0].atm && mark.value <= sampleData[sampleData.length - 1].atm)
  drawViewerThermometer({
    x: config.thermoRightX,
    value: pressureAtm,
    min: sampleData[0].atm,
    max: sampleData[sampleData.length - 1].atm,
    label: 'Pressão',
    valueLabel: formatPressureAtm(pressureAtm),
    marks,
    accent: '#cc2832',
    side: 'left',
    scaleFn: pressureThermoScale
  })
}

function strongestBond(a, b, phaseStrength, jitter) {
  const candidates = [
    { hx: a.h1.x, hy: a.h1.y, ox: b.pos.x, oy: b.pos.y, donor: 'a1' },
    { hx: a.h2.x, hy: a.h2.y, ox: b.pos.x, oy: b.pos.y, donor: 'a2' },
    { hx: b.h1.x, hy: b.h1.y, ox: a.pos.x, oy: a.pos.y, donor: 'b1' },
    { hx: b.h2.x, hy: b.h2.y, ox: a.pos.x, oy: a.pos.y, donor: 'b2' }
  ]
  let best = null
  for (const c of candidates) {
    const dx = c.ox - c.hx
    const dy = c.oy - c.hy
    const dist = Math.hypot(dx, dy)
    const dirx = dx / (dist || 1)
    const diry = dy / (dist || 1)
    let donorOx, donorOy
    if (c.donor === 'a1' || c.donor === 'a2') {
      donorOx = a.pos.x
      donorOy = a.pos.y
    } else {
      donorOx = b.pos.x
      donorOy = b.pos.y
    }
    const hdx = c.hx - donorOx
    const hdy = c.hy - donorOy
    const hlen = Math.hypot(hdx, hdy) || 1
    const align = Math.max(0, (hdx / hlen) * dirx + (hdy / hlen) * diry)
    const proximity = clamp(1 - (dist - 16 * config.scale) / (96 * config.scale), 0, 1)
    const score = Math.pow(proximity, 1.05) * Math.pow(align, 1.55) * phaseStrength * jitter
    if (!best || score > best.score) best = { ...c, dist, score }
  }
  return best
}

function drawHydrogenBonds(levels, temp, time) {
  const phaseStrength = levels.solid * (0.98 - smoothstep(-2, 12, temp) * 0.18) + levels.liquid * 0.92 + levels.vapor * 0.04
  const showStructuredIce = levels.solid > 0.24 && levels.solid >= levels.liquid && levels.vapor < 0.22

  if (showStructuredIce) {
    prevBondStrength.clear()
    const alpha = 0.34 + levels.solid * 0.36
    const width = (2.35 + levels.solid * 0.5) * config.scale
    solidReferenceBondPairs.forEach(({ from, to }, index) => {
      const pulse = 0.03 * Math.sin(time * 2.2 + index * 0.85)
      drawBondBetween(molecules[from], molecules[to], alpha + pulse, width)
    })
    return
  }

  const nextMap = new Map()
  for (let i = 0; i < molecules.length; i++) {
    for (let j = i + 1; j < molecules.length; j++) {
      const jitter = 0.78 + 0.22 * Math.sin(time * 7 + i * 0.9 + j * 1.2)
      const bond = strongestBond(molecules[i], molecules[j], phaseStrength, jitter)
      if (!bond || bond.score < 0.045) continue
      const key = `${i}-${j}`
      nextMap.set(key, bond.score)
      const prev = prevBondStrength.get(key) || 0
      if (prev > 0.36 && bond.score < 0.12) {
        spawnBreak((bond.hx + bond.ox) * 0.5, (bond.hy + bond.oy) * 0.5, prev)
      }
      ctx.save()
      ctx.lineWidth = (1.4 + bond.score * 2.6) * config.scale
      ctx.strokeStyle = `rgba(199,142,63,${0.14 + bond.score * 0.78})`
      ctx.setLineDash([5 * config.scale, 5 * config.scale])
      ctx.beginPath()
      ctx.moveTo(bond.hx, bond.hy)
      const mx = (bond.hx + bond.ox) * 0.5 + Math.sin(time * 5 + i + j) * 3.2 * config.scale * levels.liquid
      const my = (bond.hy + bond.oy) * 0.5 + Math.cos(time * 4 + i - j) * 2.8 * config.scale * levels.liquid
      ctx.quadraticCurveTo(mx, my, bond.ox, bond.oy)
      ctx.stroke()
      ctx.restore()
    }
  }

  prevBondStrength.clear()
  nextMap.forEach((value, key) => prevBondStrength.set(key, value))
}

function drawMolecule(m) {
  const lineW = 4.2 * config.scale
  const hR = 8.5 * config.scale
  const oR = 19 * config.scale
  ctx.lineCap = 'round'
  ctx.strokeStyle = 'rgba(43,84,110,0.62)'
  ctx.lineWidth = lineW
  ctx.beginPath()
  ctx.moveTo(m.pos.x, m.pos.y)
  ctx.lineTo(m.h1.x, m.h1.y)
  ctx.moveTo(m.pos.x, m.pos.y)
  ctx.lineTo(m.h2.x, m.h2.y)
  ctx.stroke()

  const og = ctx.createRadialGradient(m.pos.x - 5 * config.scale, m.pos.y - 6 * config.scale, 3 * config.scale, m.pos.x, m.pos.y, oR)
  og.addColorStop(0, '#d9f5ff')
  og.addColorStop(0.3, '#4cc7ff')
  og.addColorStop(1, '#1b8fd1')
  ctx.fillStyle = og
  ctx.beginPath()
  ctx.arc(m.pos.x, m.pos.y, oR, 0, Math.PI * 2)
  ctx.fill()
  ctx.lineWidth = 1.5 * config.scale
  ctx.strokeStyle = 'rgba(16,73,112,0.24)'
  ctx.stroke()

  const hg1 = ctx.createRadialGradient(m.h1.x - 2 * config.scale, m.h1.y - 2 * config.scale, 1 * config.scale, m.h1.x, m.h1.y, hR)
  hg1.addColorStop(0, '#f4ffd7')
  hg1.addColorStop(0.35, '#c6f37a')
  hg1.addColorStop(1, '#73bf48')
  ctx.fillStyle = hg1
  ctx.beginPath()
  ctx.arc(m.h1.x, m.h1.y, hR, 0, Math.PI * 2)
  ctx.fill()
  ctx.stroke()

  const hg2 = ctx.createRadialGradient(m.h2.x - 2 * config.scale, m.h2.y - 2 * config.scale, 1 * config.scale, m.h2.x, m.h2.y, hR)
  hg2.addColorStop(0, '#f4ffd7')
  hg2.addColorStop(0.35, '#c6f37a')
  hg2.addColorStop(1, '#73bf48')
  ctx.fillStyle = hg2
  ctx.beginPath()
  ctx.arc(m.h2.x, m.h2.y, hR, 0, Math.PI * 2)
  ctx.fill()
  ctx.stroke()

  ctx.fillStyle = 'rgba(11,67,99,0.7)'
  ctx.font = `${Math.round(13 * config.scale)}px Inter, sans-serif`
  ctx.textAlign = 'center'
  ctx.fillText('O', m.pos.x, m.pos.y + 4 * config.scale)
  ctx.fillStyle = 'rgba(45,88,29,0.78)'
  ctx.font = `${Math.round(12 * config.scale)}px Inter, sans-serif`
  ctx.fillText('H', m.h1.x, m.h1.y + 4 * config.scale)
  ctx.fillText('H', m.h2.x, m.h2.y + 4 * config.scale)

  const bisectorX = ((m.h1.x + m.h2.x) * 0.5) - m.pos.x
  const bisectorY = ((m.h1.y + m.h2.y) * 0.5) - m.pos.y
  const bisectorLen = Math.hypot(bisectorX, bisectorY) || 1
  const nx = bisectorX / bisectorLen
  const ny = bisectorY / bisectorLen
  const h1Len = Math.hypot(m.h1.x - m.pos.x, m.h1.y - m.pos.y) || 1
  const h2Len = Math.hypot(m.h2.x - m.pos.x, m.h2.y - m.pos.y) || 1
  const h1nx = (m.h1.x - m.pos.x) / h1Len
  const h1ny = (m.h1.y - m.pos.y) / h1Len
  const h2nx = (m.h2.x - m.pos.x) / h2Len
  const h2ny = (m.h2.y - m.pos.y) / h2Len

  ctx.font = `${Math.round(11 * config.scale)}px Inter, sans-serif`
  ctx.fillStyle = 'rgba(12,85,122,0.46)'
  ctx.fillText('δ−', m.pos.x - nx * 24 * config.scale, m.pos.y - ny * 24 * config.scale + 3 * config.scale)
  ctx.fillStyle = 'rgba(93,125,28,0.54)'
  ctx.fillText('δ+', m.h1.x + h1nx * 12 * config.scale, m.h1.y + h1ny * 12 * config.scale + 3 * config.scale)
  ctx.fillText('δ+', m.h2.x + h2nx * 12 * config.scale, m.h2.y + h2ny * 12 * config.scale + 3 * config.scale)
}

function waterGeometry(cx, cy, angle) {
  const hr = 26 * config.scale
  const half = 0.91
  return {
    pos: { x: cx, y: cy },
    angle,
    h1: { x: cx + Math.cos(angle - half) * hr, y: cy + Math.sin(angle - half) * hr },
    h2: { x: cx + Math.cos(angle + half) * hr, y: cy + Math.sin(angle + half) * hr }
  }
}

function drawBondBetween(a, b, alpha = 0.5, width = 2.4 * config.scale) {
  const hydrogens = [a.h1, a.h2]
  let donor = hydrogens[0]
  let dist = Math.hypot(b.pos.x - donor.x, b.pos.y - donor.y)
  const d2 = Math.hypot(b.pos.x - hydrogens[1].x, b.pos.y - hydrogens[1].y)
  if (d2 < dist) {
    donor = hydrogens[1]
    dist = d2
  }
  ctx.save()
  ctx.lineWidth = width
  ctx.strokeStyle = `rgba(199,142,63,${alpha})`
  ctx.setLineDash([5 * config.scale, 5 * config.scale])
  ctx.beginPath()
  ctx.moveTo(donor.x, donor.y)
  const mx = (donor.x + b.pos.x) * 0.5
  const my = (donor.y + b.pos.y) * 0.5 - 3 * config.scale
  ctx.quadraticCurveTo(mx, my, b.pos.x, b.pos.y)
  ctx.stroke()
  ctx.restore()
}


function buildReferenceCluster(center, defs, time, phaseShift = 0) {
  return defs.map((def, index) => {
    const wobbleX = Math.sin(time * def.driftX + index * 0.9 + phaseShift) * def.jitter * 1.45 * config.scale
    const wobbleY = Math.cos(time * def.driftY + index * 0.72 + phaseShift * 0.6) * def.jitter * 1.45 * config.scale
    const twist = Math.sin(time * (def.driftX * 0.6 + 0.25) + index * 0.8 + phaseShift) * def.twist * 1.45
    const cx = center.x + def.offset[0] * config.scale + wobbleX
    const cy = center.y + def.offset[1] * config.scale + wobbleY
    return waterGeometry(cx, cy, def.angle + twist)
  })
}

function buildDynamicReferenceCluster(center, defs, time, options = {}) {
  const {
    phaseShift = 0,
    orbitX = 0,
    orbitY = 0,
    jitterScale = 1,
    twistScale = 1,
    speedScale = 1
  } = options

  return defs.map((def, index) => {
    const wobbleX = Math.sin(time * def.driftX * speedScale + index * 1.06 + phaseShift) * def.jitter * 1.9 * jitterScale * config.scale
    const wobbleY = Math.cos(time * def.driftY * speedScale + index * 0.84 + phaseShift * 0.72) * def.jitter * 1.9 * jitterScale * config.scale
    const orbitHX = Math.sin(time * (1.1 + index * 0.03) * speedScale + phaseShift + index * 0.4) * orbitX * config.scale
    const orbitHY = Math.cos(time * (1.24 + index * 0.04) * speedScale + phaseShift * 0.8 + index * 0.35) * orbitY * config.scale
    const twist = Math.sin(time * (def.driftX * 0.82 + 0.34) * speedScale + index * 0.88 + phaseShift) * def.twist * 2.0 * twistScale
    const cx = center.x + def.offset[0] * config.scale + wobbleX + orbitHX
    const cy = center.y + def.offset[1] * config.scale + wobbleY + orbitHY
    return waterGeometry(cx, cy, def.angle + twist)
  })
}

function drawReferenceBond(donorMol, acceptorMol, alpha = 0.5, width = 2.4 * config.scale) {
  drawBondBetween(donorMol, acceptorMol, alpha, width)
}

function drawTripleReferenceScene(time) {
  const solidCenter = { x: config.panelCenters[0], y: config.clusterY + 6 * config.scale }
  const liquidCenter = { x: config.panelCenters[1], y: config.clusterY + 10 * config.scale }
  const vaporCenter = { x: config.panelCenters[2], y: config.clusterY + 4 * config.scale }

  const solidDefs = criticalSolidOffsets.map((offset, i) => ({
    offset,
    angle: criticalSolidAngles[i % criticalSolidAngles.length],
    jitter: 2.4,
    driftX: 1.18 + i * 0.03,
    driftY: 1.06 + i * 0.02,
    twist: 0.035
  }))

  const liquidDefs = criticalLiquidOffsets.map((offset, i) => ({
    offset,
    angle: criticalLiquidAngles[i % criticalLiquidAngles.length],
    jitter: 3.6,
    driftX: 1.16 + i * 0.04,
    driftY: 1.08 + i * 0.03,
    twist: 0.075
  }))

  const vaporDefs = criticalVaporOffsets.map((offset, i) => ({
    offset,
    angle: criticalVaporAngles[i % criticalVaporAngles.length],
    jitter: 5.8,
    driftX: 1.28 + i * 0.05,
    driftY: 1.22 + i * 0.04,
    twist: 0.13
  }))

  const solidMol = buildDynamicReferenceCluster(solidCenter, solidDefs, time, {
    phaseShift: 0.12,
    orbitX: 1.8,
    orbitY: 1.6,
    jitterScale: 1.1,
    twistScale: 1.04,
    speedScale: 1.04
  })

  const liquidMol = buildDynamicReferenceCluster(liquidCenter, liquidDefs, time, {
    phaseShift: 0.46,
    orbitX: 4.8,
    orbitY: 4.1,
    jitterScale: 1.22,
    twistScale: 1.14,
    speedScale: 1.12
  })

  const vaporMol = buildDynamicReferenceCluster(vaporCenter, vaporDefs, time, {
    phaseShift: 0.92,
    orbitX: 12.2,
    orbitY: 13.6,
    jitterScale: 1.42,
    twistScale: 1.2,
    speedScale: 1.22
  })

  for (let i = 0; i < solidMol.length; i++) {
    drawBondBetween(solidMol[i], solidMol[(i + 1) % solidMol.length], 0.5, 2.3 * config.scale)
  }

  const liquidPairs = [
    [0, 1],
    [1, 2],
    [2, 5],
    [4, 0],
    [4, 3],
    [3, 2]
  ]

  liquidPairs.forEach(([a, b], idx) => {
    const first = idx % 2 === 0 ? liquidMol[a] : liquidMol[b]
    const second = idx % 2 === 0 ? liquidMol[b] : liquidMol[a]
    drawBondBetween(first, second, 0.32, 2.0 * config.scale)
  })

  vaporMol.forEach((mol, index) => {
    const partner = vaporMol[(index + 1) % vaporMol.length]
    if (index % 2 === 0) drawBondBetween(mol, partner, 0.1, 1.45 * config.scale)
  })

  solidMol.forEach(drawMolecule)
  liquidMol.forEach(drawMolecule)
  vaporMol.forEach(drawMolecule)
}

function drawCriticalComparison() {
  const center = { x: config.width * 0.5, y: config.clusterY + 6 * config.scale }
  const supercriticalMol = buildDynamicReferenceCluster(center, supercriticalReference, state.time, {
    phaseShift: 0.64,
    orbitX: 12.5,
    orbitY: 14.5,
    jitterScale: 1.55,
    twistScale: 1.3,
    speedScale: 1.12
  })

  supercriticalBondPairs.forEach(([from, to], idx) => {
    const alpha = idx < 8 ? 0.22 : 0.15
    const width = idx < 8 ? 1.95 * config.scale : 1.55 * config.scale
    drawBondBetween(supercriticalMol[from], supercriticalMol[to], alpha, width)
  })

  supercriticalMol.forEach(drawMolecule)
}

function drawHeatWaves(temp, time) {
  const strength = clamp((temp - TEMP_MIN_K) / Math.max(TEMP_MAX_K - TEMP_MIN_K, 1), 0, 1)
  const baseY = config.height * 0.93
  ctx.save()
  for (let i = 0; i < 4; i++) {
    ctx.beginPath()
    const amp = (7 + i * 3 + strength * 18) * config.scale
    const y = baseY + i * 8 * config.scale
    for (let x = config.width * 0.18; x <= config.width * 0.92; x += 10) {
      const nx = x - config.width * 0.18
      const wave = Math.sin(nx * 0.02 + time * (2.4 + i * 0.25)) * amp
      if (x === config.width * 0.18) ctx.moveTo(x, y + wave)
      else ctx.lineTo(x, y + wave)
    }
    ctx.strokeStyle = `rgba(255,126,84,${0.04 + strength * 0.08 - i * 0.008})`
    ctx.lineWidth = (2 + i * 0.25) * config.scale
    ctx.stroke()
  }
  ctx.restore()
}

function drawTag(x, y, text, color) {
  ctx.save()
  ctx.font = `${Math.round(12 * config.scale)}px Inter, sans-serif`
  const w = ctx.measureText(text).width + 22 * config.scale
  const h = 28 * config.scale
  drawRoundedRect(x, y, w, h, h / 2)
  ctx.fillStyle = 'rgba(255,255,255,0.92)'
  ctx.fill()
  ctx.strokeStyle = 'rgba(30,62,84,0.08)'
  ctx.stroke()
  ctx.fillStyle = color
  ctx.beginPath()
  ctx.arc(x + 13 * config.scale, y + h / 2, 4.5 * config.scale, 0, Math.PI * 2)
  ctx.fill()
  ctx.fillStyle = '#24445d'
  ctx.textAlign = 'left'
  ctx.fillText(text, x + 22 * config.scale, y + 18.5 * config.scale)
  ctx.restore()
}

function wrapText(text, x, y, maxWidth, lineHeight, font, color) {
  ctx.font = font
  ctx.fillStyle = color
  const words = text.split(' ')
  let line = ''
  let yy = y
  for (let n = 0; n < words.length; n++) {
    const testLine = line + words[n] + ' '
    const testWidth = ctx.measureText(testLine).width
    if (testWidth > maxWidth && n > 0) {
      ctx.fillText(line, x, yy)
      line = words[n] + ' '
      yy += lineHeight
    } else {
      line = testLine
    }
  }
  ctx.fillText(line, x, yy)
}

function drawDescription(temp, levels) {
  let headline = ''
  let body = ''
  if (shouldShowCriticalComparison()) {
    headline = 'Ponto crítico: regime supercrítico'
    body = 'Nessa condição, líquido e vapor deixam de constituir fases separadas. O sistema passa a ser representado como um único fluido supercrítico, com alta mobilidade molecular e densidade intermediária.'
  } else if (shouldShowTripleEquilibrium()) {
    headline = 'Ponto triplo: coexistência de três fases'
    body = 'Nesta região, o visualizador distribui as moléculas entre gelo, líquido e vapor em equilíbrio dinâmico. As relações de equilíbrio químico entre H₂O(s), H₂O(l) e H₂O(g) indicam a coexistência simultânea das três fases.'
  } else if (temp <= MELT_K) {
    headline = 'Faixa de estabilidade do sólido'
    body = 'Em temperaturas mais baixas, a água tende a permanecer em arranjo mais ordenado. O aquecimento progressivo aumenta a vibração e reduz a estabilidade dessa organização cristalina.'
  } else if (temp < state.actualBoil) {
    headline = 'Faixa de estabilidade do líquido'
    body = 'Na região líquida, o aumento de temperatura intensifica a mobilidade molecular, enquanto a pressão modifica o grau de compactação média do conjunto.'
  } else {
    headline = 'Predomínio da fase gasosa'
    body = 'Ao se ultrapassar a faixa de coexistência líquido–vapor para a pressão considerada, a fase gasosa passa a ocupar o volume disponível com maior liberdade de movimento. Pressões mais altas, entretanto, ainda restringem a expansão relativa do sistema.'
  }

  const boxW = config.width * 0.60
  const boxH = 108 * config.scale
  const x = (config.width - boxW) * 0.5
  const y = config.descriptionY - boxH / 2
  drawRoundedRect(x, y, boxW, boxH, 18 * config.scale)
  const bg = ctx.createLinearGradient(x, y, x, y + boxH)
  bg.addColorStop(0, 'rgba(20,38,52,0.18)')
  bg.addColorStop(1, 'rgba(20,38,52,0.10)')
  ctx.fillStyle = bg
  ctx.fill()
  ctx.lineWidth = 1.2 * config.scale
  ctx.strokeStyle = 'rgba(255,255,255,0.08)'
  ctx.stroke()

  ctx.textAlign = 'left'
  ctx.fillStyle = 'rgba(237,243,255,0.96)'
  ctx.font = `${Math.round(21 * config.scale)}px Inter, sans-serif`
  ctx.fillText(headline, x + 18 * config.scale, y + 30 * config.scale)

  wrapText(body, x + 18 * config.scale, y + 54 * config.scale, boxW - 44 * config.scale, 19 * config.scale, `${Math.round(14 * config.scale)}px Inter, sans-serif`, 'rgba(237,243,255,0.88)')
  const tagX = x + boxW - 172 * config.scale
  const tagY = y + 16 * config.scale
  const tagText = shouldShowCriticalComparison()
    ? 'fase presente: supercrítico'
    : shouldShowTripleEquilibrium()
      ? 'três fases em equilíbrio'
      : levels.solid > Math.max(levels.liquid, levels.vapor)
        ? 'fase predominante: gelo'
        : levels.liquid > levels.vapor
          ? 'fase predominante: água'
          : 'fase predominante: vapor'
}

function drawLegend() {
  const x = config.width * 0.70
  const y = config.height * 0.135
  const w = 214 * config.scale
  const h = 78 * config.scale
  drawRoundedRect(x, y, w, h, 18 * config.scale)
  ctx.fillStyle = 'rgba(20,38,52,0.14)'
  ctx.fill()
  ctx.strokeStyle = 'rgba(255,255,255,0.08)'
  ctx.stroke()
  ctx.textAlign = 'left'
  ctx.fillStyle = 'rgba(237,243,255,0.96)'
  ctx.font = `${Math.round(15 * config.scale)}px Inter, sans-serif`
  ctx.fillText('Polaridade parcial', x + 16 * config.scale, y + 22 * config.scale)
  ctx.font = `${Math.round(13 * config.scale)}px Inter, sans-serif`
  ctx.fillStyle = 'rgba(237,243,255,0.8)'
  ctx.fillText('Oxigênio = δ−', x + 16 * config.scale, y + 47 * config.scale)
  ctx.fillText('Hidrogênios = δ+', x + 16 * config.scale, y + 68 * config.scale)
  ctx.fillStyle = '#1b8fd1'
  ctx.beginPath()
  ctx.arc(x + w - 44 * config.scale, y + 32 * config.scale, 10 * config.scale, 0, Math.PI * 2)
  ctx.fill()
  ctx.fillStyle = '#7cc84c'
  ctx.beginPath()
  ctx.arc(x + w - 64 * config.scale, y + 60 * config.scale, 5.5 * config.scale, 0, Math.PI * 2)
  ctx.arc(x + w - 24 * config.scale, y + 60 * config.scale, 5.5 * config.scale, 0, Math.PI * 2)
  ctx.fill()
}

function drawArrowHead(x, y, angle, color, size = 10 * config.scale) {
  ctx.save()
  ctx.translate(x, y)
  ctx.rotate(angle)
  ctx.beginPath()
  ctx.moveTo(0, 0)
  ctx.lineTo(-size, size * 0.42)
  ctx.lineTo(-size * 0.72, 0)
  ctx.lineTo(-size, -size * 0.42)
  ctx.closePath()
  ctx.fillStyle = color
  ctx.fill()
  ctx.restore()
}

function drawCurvedArrow(x1, y1, x2, y2, bend, color, width = 2.2 * config.scale) {
  const mx = (x1 + x2) * 0.5
  const my = (y1 + y2) * 0.5
  const dx = x2 - x1
  const dy = y2 - y1
  const len = Math.hypot(dx, dy) || 1
  const nx = -dy / len
  const ny = dx / len
  const cx = mx + nx * bend
  const cy = my + ny * bend

  ctx.save()
  ctx.strokeStyle = color
  ctx.lineWidth = width
  ctx.lineCap = 'round'
  ctx.setLineDash([])
  ctx.beginPath()
  ctx.moveTo(x1, y1)
  ctx.quadraticCurveTo(cx, cy, x2, y2)
  ctx.stroke()

  const t = 0.92
  const qx = (1 - t) * (1 - t) * x1 + 2 * (1 - t) * t * cx + t * t * x2
  const qy = (1 - t) * (1 - t) * y1 + 2 * (1 - t) * t * cy + t * t * y2
  const tx = 2 * (1 - t) * (cx - x1) + 2 * t * (x2 - cx)
  const ty = 2 * (1 - t) * (cy - y1) + 2 * t * (y2 - cy)
  drawArrowHead(qx, qy, Math.atan2(ty, tx), color, 9 * config.scale)
  ctx.restore()
}


function drawTripleEquilibriumArrows() {
  if (!shouldShowTripleEquilibrium()) return

  const left = panelRect(0)
  const mid = panelRect(1)
  const right = panelRect(2)

  function drawSimpleEquilibriumSymbol(x, y, w) {
    const half = w * 0.5
    const gap = 8 * config.scale
    const arrow = 18 * config.scale

    ctx.save()
    ctx.strokeStyle = '#000'
    ctx.lineWidth = 5 * config.scale
    ctx.lineCap = 'round'
    ctx.lineJoin = 'round'

    ctx.beginPath()
    ctx.moveTo(x - half, y - gap)
    ctx.lineTo(x + half, y - gap)
    ctx.moveTo(x + half - arrow, y - gap - arrow * 0.52)
    ctx.lineTo(x + half, y - gap)
    ctx.lineTo(x + half - arrow, y - gap + arrow * 0.52)

    ctx.moveTo(x + half, y + gap)
    ctx.lineTo(x - half, y + gap)
    ctx.moveTo(x - half + arrow, y + gap - arrow * 0.52)
    ctx.lineTo(x - half, y + gap)
    ctx.lineTo(x - half + arrow, y + gap + arrow * 0.52)
    ctx.stroke()
    ctx.restore()
  }

  const y = config.phaseBoxY + 248 * config.scale
  drawSimpleEquilibriumSymbol((left.x + left.w + mid.x) * 0.5, y, 66 * config.scale)
  drawSimpleEquilibriumSymbol((mid.x + mid.w + right.x) * 0.5, y, 66 * config.scale)
}

function mapDiagramX(tempK, box) {
  const tMin = 180
  const tMax = 700
  const scale = box.scale || config.scale
  return box.x + 42 * scale + clamp((tempK - tMin) / (tMax - tMin), 0, 1) * (box.w - 66 * scale)
}

function mapDiagramY(pressureAtm, box) {
  const pMin = 0.0005
  const pMax = 300
  const scale = box.scale || config.scale
  const lp = Math.log10(clamp(pressureAtm, pMin, pMax))
  const lMin = Math.log10(pMin)
  const lMax = Math.log10(pMax)
  const t = clamp((lp - lMin) / (lMax - lMin), 0, 1)
  return box.y + box.h - 34 * scale - t * (box.h - 58 * scale)
}

function vaporCurvePoint(u, box) {
  const temp = lerp(TRIPLE_K, CRITICAL_K, u)
  const logP = Math.log10(TRIPLE_ATM) + (Math.log10(CRITICAL_ATM) - Math.log10(TRIPLE_ATM)) * Math.pow(u, 1.28)
  const pressureAtm = Math.pow(10, logP)
  return { x: mapDiagramX(temp, box), y: mapDiagramY(pressureAtm, box), temp, pressureAtm }
}

function drawDiagramFocusGlow(x, y, color, radiusMul = 1) {
  const r = 22 * config.scale * radiusMul
  const g = ctx.createRadialGradient(x, y, 0, x, y, r)
  g.addColorStop(0, color)
  g.addColorStop(1, 'rgba(0,0,0,0)')
  ctx.fillStyle = g
  ctx.beginPath()
  ctx.arc(x, y, r, 0, Math.PI * 2)
  ctx.fill()
}

function drawPhaseDiagramPanel() {
  if (!phaseChart || !pctx) return

  const scale = diagramConfig.scale
  const box = {
    x: 18 * scale,
    y: 18 * scale,
    w: Math.max(280 * scale, diagramConfig.width - 36 * scale),
    h: Math.max(200 * scale, diagramConfig.height - 36 * scale),
    scale
  }
  const step = tutorialSteps[state.tutorialStep] || tutorialSteps[0]
  const graphFont = `${Math.round(14 * scale)}px Inter, sans-serif`
  const tickFont = `${Math.round(11 * scale)}px Inter, sans-serif`

  pctx.clearRect(0, 0, diagramConfig.width, diagramConfig.height)

  drawRoundedRectOn(pctx, box.x, box.y, box.w, box.h, 20 * scale)
  pctx.fillStyle = 'rgba(9,16,30,0.78)'
  pctx.fill()
  pctx.strokeStyle = 'rgba(255,255,255,0.08)'
  pctx.stroke()

  const x0 = box.x + 64 * scale
  const y0 = box.y + box.h - 46 * scale
  const x1 = box.x + box.w - 28 * scale
  const y1 = box.y + 28 * scale

  pctx.save()
  pctx.beginPath()
  pctx.rect(x0, y1, x1 - x0, y0 - y1)
  pctx.clip()

  const tMarks = [200, 273.16, 373.15, 500, 647.1]
  const pMarks = [0.001, 0.01, 0.1, 1, 10, 100, 217.7]

  pctx.strokeStyle = 'rgba(255,255,255,0.09)'
  pctx.lineWidth = 1 * scale
  tMarks.forEach(v => {
    const x = mapDiagramX(v, box)
    pctx.beginPath()
    pctx.moveTo(x, y1)
    pctx.lineTo(x, y0)
    pctx.stroke()
  })
  pMarks.forEach(v => {
    const y = mapDiagramY(v, box)
    pctx.beginPath()
    pctx.moveTo(x0, y)
    pctx.lineTo(x1, y)
    pctx.stroke()
  })

  pctx.strokeStyle = 'rgba(255,255,255,0.22)'
  pctx.lineWidth = 1.2 * scale
  pctx.beginPath()
  pctx.moveTo(x0, y1)
  pctx.lineTo(x0, y0)
  pctx.lineTo(x1, y0)
  pctx.stroke()

  const tripleX = mapDiagramX(TRIPLE_K, box)
  const tripleY = mapDiagramY(TRIPLE_ATM, box)
  const critX = mapDiagramX(CRITICAL_K, box)
  const critY = mapDiagramY(CRITICAL_ATM, box)

  pctx.strokeStyle = 'rgba(143,220,255,0.88)'
  pctx.lineWidth = 2.2 * scale

  pctx.beginPath()
  pctx.moveTo(mapDiagramX(185, box), mapDiagramY(0.00055, box))
  pctx.quadraticCurveTo(mapDiagramX(228, box), mapDiagramY(0.0018, box), tripleX, tripleY)
  pctx.stroke()

  pctx.beginPath()
  pctx.moveTo(tripleX, tripleY)
  pctx.quadraticCurveTo(mapDiagramX(262, box), mapDiagramY(1.2, box), mapDiagramX(246, box), mapDiagramY(220, box))
  pctx.stroke()

  pctx.beginPath()
  const satRows = sampleData.filter(row => row.k >= TRIPLE_K && row.atm <= CRITICAL_ATM * 1.001)
  satRows.forEach((row, i) => {
    const x = mapDiagramX(row.k, box)
    const y = mapDiagramY(row.atm, box)
    if (i === 0) pctx.moveTo(x, y)
    else pctx.lineTo(x, y)
  })
  pctx.stroke()

  pctx.fillStyle = 'rgba(201,229,255,0.72)'
  pctx.font = graphFont
  pctx.textAlign = 'center'
  pctx.textBaseline = 'middle'
  pctx.fillText('Sólido', mapDiagramX(224, box), mapDiagramY(22, box))
  pctx.fillText('Líquido', mapDiagramX(335, box), mapDiagramY(13, box))
  pctx.fillText('Gasoso', mapDiagramX(540, box), mapDiagramY(0.035, box))

  const glow = (x, y, color, radiusMul = 1) => {
    const r = 22 * scale * radiusMul
    const g = pctx.createRadialGradient(x, y, 0, x, y, r)
    g.addColorStop(0, color)
    g.addColorStop(1, 'rgba(0,0,0,0)')
    pctx.fillStyle = g
    pctx.beginPath()
    pctx.arc(x, y, r, 0, Math.PI * 2)
    pctx.fill()
  }

  if (step.diagramFocus === 'triple') glow(tripleX, tripleY, 'rgba(78,213,255,0.34)', 1.35)
  if (step.diagramFocus === 'critical') glow(critX, critY, 'rgba(255,140,90,0.34)', 1.45)
  if (step.diagramFocus === 'vaporCurve' || step.diagramFocus === 'clapeyron' || step.diagramFocus === 'equations') {
    const p = vaporCurvePoint(0.56, box)
    glow(p.x, p.y, 'rgba(122,125,255,0.22)', 1.8)
  }
  if (step.diagramFocus === 'fusion') {
    const fx = mapDiagramX(259, box)
    const fy = mapDiagramY(24, box)
    glow(fx, fy, 'rgba(145,255,214,0.26)', 1.5)
  }

  glow(tripleX, tripleY, 'rgba(78,213,255,0.18)', 1)
  glow(critX, critY, 'rgba(255,140,90,0.18)', 1)

  pctx.fillStyle = '#7edbff'
  pctx.beginPath()
  pctx.arc(tripleX, tripleY, 4.2 * scale, 0, Math.PI * 2)
  pctx.fill()
  pctx.fillStyle = '#ff9c6a'
  pctx.beginPath()
  pctx.arc(critX, critY, 4.8 * scale, 0, Math.PI * 2)
  pctx.fill()

  pctx.font = graphFont
  pctx.fillStyle = 'rgba(237,243,255,0.82)'
  pctx.textBaseline = 'middle'
  pctx.textAlign = 'left'
  pctx.fillText('ponto triplo', Math.min(tripleX + 10 * scale, x1 - 118 * scale), Math.max(tripleY - 10 * scale, y0 + 18 * scale))
  pctx.textAlign = 'right'
  pctx.fillText('ponto crítico', Math.min(critX - 10 * scale, x1 - 18 * scale), Math.max(critY + 16 * scale, y0 + 18 * scale))

  const currentAtm = mmHgToAtm(state.pressureMmHg)
  const cx = mapDiagramX(state.temp, box)
  const cy = mapDiagramY(currentAtm, box)
  glow(cx, cy, 'rgba(255,255,255,0.26)', 1.15)
  pctx.strokeStyle = '#ffffff'
  pctx.lineWidth = 2.2 * scale
  pctx.beginPath()
  pctx.arc(cx, cy, 6.6 * scale, 0, Math.PI * 2)
  pctx.stroke()
  pctx.fillStyle = '#ffffff'
  pctx.beginPath()
  pctx.arc(cx, cy, 2.6 * scale, 0, Math.PI * 2)
  pctx.fill()
  pctx.restore()

  pctx.font = tickFont
  pctx.fillStyle = 'rgba(237,243,255,0.66)'

  pctx.textBaseline = 'top'
  tMarks.forEach(v => {
    const x = mapDiagramX(v, box)
    const label = v === 273.16 ? '273,16 K' : v === 647.1 ? '647,1 K' : `${Math.round(v)} K`
    const metrics = pctx.measureText(label).width
    const tx = clamp(x - metrics / 2, x0 + 4 * scale, x1 - metrics - 4 * scale)
    pctx.fillText(label, tx, y0 + 12 * scale)
  })

  pctx.textBaseline = 'middle'
  pMarks.forEach(v => {
    const y = mapDiagramY(v, box)
    const label = v === 217.7 ? '217,7 atm' : `${String(v).replace('.', ',')} atm`
    pctx.textAlign = 'right'
    pctx.fillText(label, x0 - 10 * scale, y)
  })

  pctx.textAlign = 'left'
  pctx.textBaseline = 'alphabetic'
}

function render() {
  const levels = computeMolecules(state.temp, state.time)
  drawBackground(levels, state.temp)
  drawTitles(levels)
  drawTripleEquilibriumArrows()
  drawTemperatureThermometer(state.temp)
  drawPressureThermometer(state.pressureMmHg)
  drawHeatWaves(state.temp, state.time)
  if (shouldShowCriticalComparison()) {
    drawCriticalComparison()
  } else if (shouldShowTripleEquilibrium()) {
    drawTripleReferenceScene(state.time)
  } else {
    drawHydrogenBonds(levels, state.temp, state.time)
    molecules.forEach(drawMolecule)
  }
  updateParticles()
  drawParticles()
  drawPhaseDiagramPanel()
}

function syncPressureUI() {
  pressureSlider.min = sampleData[0].mmHg.toFixed(3)
  pressureSlider.max = sampleData[sampleData.length - 1].mmHg.toFixed(3)
  pressureSlider.step = '0.001'
  pressureSlider.value = state.pressureMmHg.toFixed(3)
  if (pressureRead) pressureRead.textContent = formatPressureMmHg(state.pressureMmHg)
  if (pressureAlt) pressureAlt.textContent = formatPressureAtm(mmHgToAtm(state.pressureMmHg))
  if (pressureInput) pressureInput.value = state.unit === 'mmHg' ? state.pressureMmHg.toFixed(3) : mmHgToAtm(state.pressureMmHg).toFixed(3)
  if (unitSelect) unitSelect.value = state.unit
  if (sampleSelect) sampleSelect.value = String(findNearestSampleIndex(state.pressureMmHg))
}

function syncTempUI() {
  state.temp = clamp(state.temp, TEMP_MIN_K, TEMP_MAX_K)
  slider.min = TEMP_MIN_K.toFixed(2)
  slider.max = TEMP_MAX_K.toFixed(2)
  slider.step = '0.01'
  slider.value = state.temp.toFixed(2)
  tempRead.textContent = formatKelvin(state.temp)
  tempMaxRead.textContent = formatCelsiusFromK(state.temp)
}

function updateDataUI() {
  const row = state.currentRow || interpolateSaturationRow(state.pressureMmHg)
  boilNistRead.textContent = formatTempPairK(row.k)
  densityRead.textContent = `${formatNumber(row.rhoL, 3)} g/mL`
  viscosityRead.textContent = `${row.muL.toExponential(3).replace('.', ',')} Pa·s`
  surfaceRead.textContent = `${formatNumber(row.sigma, 4)} N/m`
  if (sourceRead) sourceRead.innerHTML = ''
}

function updateSummaries() {
  const phase = shouldShowCriticalComparison() ? 'fluido supercrítico' : shouldShowTripleEquilibrium() ? 'gelo, água líquida e vapor ao mesmo tempo' : state.temp <= MELT_K ? 'gelo' : state.temp < state.actualBoil ? 'água líquida' : 'vapor'
  const row = state.currentRow || interpolateSaturationRow(state.pressureMmHg)
  if (phaseSummary) phaseSummary.textContent = ''
  if (conversionSummary) conversionSummary.textContent = `${formatPressureMmHg(state.pressureMmHg)} correspondem a ${formatPressureAtm(mmHgToAtm(state.pressureMmHg))}. Nesse ponto, a água líquida fica com densidade de ${formatNumber(row.rhoL, 3)} g/mL e tensão superficial de ${formatNumber(row.sigma, 4)} N/m.`
  if (interpNote) interpNote.textContent = ''
}


function setPressureState(mmHg) {
  state.pressureMmHg = clamp(mmHg, sampleData[0].mmHg, sampleData[sampleData.length - 1].mmHg)
  state.currentRow = interpolateSaturationRow(state.pressureMmHg)
  state.actualBoil = state.currentRow.k
}

function syncAllUI() {
  syncPressureUI()
  syncTempUI()
  updateDataUI()
  updateSummaries()
}

function applyTutorialStep(index, immediate = false) {
  state.tutorialStep = (index + tutorialSteps.length) % tutorialSteps.length
  state.forceTripleView = false
  state.forceCriticalView = false
  const step = tutorialSteps[state.tutorialStep]
  state.targetTemp = clamp(step.temp, TEMP_MIN_K, TEMP_MAX_K)
  state.targetPressureMmHg = clamp(step.pressureMmHg, sampleData[0].mmHg, sampleData[sampleData.length - 1].mmHg)
  state.tutorialTimer = 0
  if (immediate) {
    setPressureState(state.targetPressureMmHg)
    state.temp = state.targetTemp
    state.guideActive = false
    syncAllUI()
  } else {
    state.guideActive = true
  }
  if (tutorialStepTag) tutorialStepTag.textContent = `Etapa ${state.tutorialStep + 1}`
  if (tutorialTitle) tutorialTitle.textContent = step.title
  if (tutorialBody) tutorialBody.innerHTML = step.body
  if (tutorialMini) tutorialMini.innerHTML = (step.chips || []).map(chip => `<span class="pill">${chip}</span>`).join('')
  if (tutorialNote) tutorialNote.innerHTML = step.note
  if (tutorialEquation) tutorialEquation.innerHTML = step.equation
  if (tutorialFocus) tutorialFocus.textContent = step.focus
  if (tutorialProgressBar) tutorialProgressBar.style.width = `${((state.tutorialStep + 1) / tutorialSteps.length) * 100}%`
  if (tutorialPrev) tutorialPrev.disabled = tutorialSteps.length < 2
  if (tutorialNext) tutorialNext.disabled = tutorialSteps.length < 2
  if (tutorialAuto) tutorialAuto.textContent = state.tutorialAuto ? '⏸ Auto' : '▶ Auto'
}

function animateGuide(dt) {
  if (!state.guideActive) return
  const nextTemp = lerp(state.temp, state.targetTemp, 1 - Math.exp(-dt * 2.4))
  const nextPressure = lerp(state.pressureMmHg, state.targetPressureMmHg, 1 - Math.exp(-dt * 2.2))
  state.temp = Math.abs(nextTemp - state.targetTemp) < 0.03 ? state.targetTemp : nextTemp
  setPressureState(Math.abs(nextPressure - state.targetPressureMmHg) < 0.08 ? state.targetPressureMmHg : nextPressure)
  syncAllUI()
  if (Math.abs(state.temp - state.targetTemp) < 0.03 && Math.abs(state.pressureMmHg - state.targetPressureMmHg) < 0.08) {
    state.guideActive = false
  }
}

function updateTutorialAuto(dt) {
  if (!state.tutorialAuto) return
  state.tutorialTimer += dt * 1000
  const step = tutorialSteps[state.tutorialStep]
  const limit = step && step.autoMs ? step.autoMs : 6500
  if (state.tutorialTimer >= limit) {
    applyTutorialStep(state.tutorialStep + 1, false)
  }
}

function applyPressure(mmHg) {
  setPressureState(mmHg)
  syncAllUI()
}

function populateSamples() {
  sampleData.forEach((row, index) => {
    const option = document.createElement('option')
    option.value = String(index)
    option.textContent = `${formatTempPairK(row.k)} · ${formatPressureAtm(row.atm)} · ${formatPressureMmHg(row.mmHg)}`
    sampleSelect.appendChild(option)
  })
}


function getSceneLocalPoint(evt) {
  const rect = canvas.getBoundingClientRect()
  return {
    x: evt.clientX - rect.left,
    y: evt.clientY - rect.top
  }
}

function pointInBounds(point, bounds) {
  return !!bounds && point.x >= bounds.x && point.x <= bounds.x + bounds.w && point.y >= bounds.y && point.y <= bounds.y + bounds.h
}

function setThermometerFromPoint(kind, point) {
  const norm = clamp((config.thermoBottom - point.y) / Math.max(config.thermoBottom - config.thermoTop, 1), 0, 1)
  state.guideActive = false
  state.forceTripleView = false
  state.forceCriticalView = false
  if (kind === 'temp') {
    state.temp = clamp(TEMP_MIN_K + norm * (TEMP_MAX_K - TEMP_MIN_K), TEMP_MIN_K, TEMP_MAX_K)
    syncTempUI()
    updateSummaries()
    return
  }
  const minAtm = sampleData[0].atm
  const maxAtm = sampleData[sampleData.length - 1].atm
  const logMin = Math.log10(Math.max(minAtm, 0.000001))
  const logMax = Math.log10(Math.max(maxAtm, minAtm + 0.000001))
  const atm = Math.pow(10, logMin + norm * (logMax - logMin))
  applyPressure(atmToMmHg(atm))
}

function startThermoPointer(evt) {
  const point = getSceneLocalPoint(evt)
  let kind = null
  if (pointInBounds(point, config.tempThermoBounds)) kind = 'temp'
  else if (pointInBounds(point, config.pressureThermoBounds)) kind = 'pressure'
  if (!kind) return
  state.activeThermo = kind
  state.activePointerId = evt.pointerId
  if (canvas.setPointerCapture) canvas.setPointerCapture(evt.pointerId)
  setThermometerFromPoint(kind, point)
  evt.preventDefault()
}

function moveThermoPointer(evt) {
  if (!state.activeThermo) return
  if (state.activePointerId != null && evt.pointerId !== state.activePointerId) return
  const point = getSceneLocalPoint(evt)
  setThermometerFromPoint(state.activeThermo, point)
  evt.preventDefault()
}

function endThermoPointer(evt) {
  if (state.activePointerId != null && evt.pointerId !== state.activePointerId) return
  state.activeThermo = null
  state.activePointerId = null
}

function tick(ts) {
  if (!state.lastTime) state.lastTime = ts
  const dt = Math.min(0.04, (ts - state.lastTime) / 1000)
  state.lastTime = ts
  state.dt = dt
  state.time += dt
  animateGuide(dt)
  updateTutorialAuto(dt)
  render()
  requestAnimationFrame(tick)
}

if (pressureSlider) {
  pressureSlider.addEventListener('input', e => {
    state.guideActive = false
    state.forceTripleView = false
    state.forceCriticalView = false
    applyPressure(Number(e.target.value))
  })
}

if (pressureInput) {
  pressureInput.addEventListener('input', e => {
    const v = Number(e.target.value)
    if (!Number.isFinite(v)) return
    state.guideActive = false
    state.forceTripleView = false
    state.forceCriticalView = false
    const mmHg = state.unit === 'mmHg' ? v : atmToMmHg(v)
    applyPressure(mmHg)
  })
}

if (unitSelect) {
  unitSelect.addEventListener('change', e => {
    state.unit = e.target.value
    syncPressureUI()
    updateDataUI()
  })
}

if (sampleSelect) {
  sampleSelect.addEventListener('change', e => {
    const row = sampleData[Number(e.target.value)]
    if (!row) return
    state.guideActive = false
    state.forceTripleView = false
    state.forceCriticalView = false
    applyPressure(row.mmHg)
  })
}

if (slider) {
  slider.addEventListener('input', e => {
    state.guideActive = false
    state.forceTripleView = false
    state.forceCriticalView = false
    state.temp = clamp(Number(e.target.value), TEMP_MIN_K, TEMP_MAX_K)
    syncTempUI()
    updateSummaries()
  })
}

if (playBtn) {
  playBtn.addEventListener('click', () => {
    state.playing = !state.playing
    playBtn.textContent = state.playing ? 'Pausar' : 'Continuar'
  })
}

if (resetBtn) {
  resetBtn.addEventListener('click', () => {
    state.temp = MELT_K
    particles.length = 0
    prevBondStrength.clear()
    molecules.forEach(m => {
      m.vaporX = NaN
      m.vaporY = NaN
      m.vaporVX = 0
      m.vaporVY = 0
    })
    syncTempUI()
    updateSummaries()
  })
}


if (tutorialPrev) {
  tutorialPrev.addEventListener('click', () => applyTutorialStep(state.tutorialStep - 1, false))
}

if (tutorialNext) {
  tutorialNext.addEventListener('click', () => applyTutorialStep(state.tutorialStep + 1, false))
}

if (tutorialRestart) {
  tutorialRestart.addEventListener('click', () => applyTutorialStep(0, true))
}

if (tutorialAuto) {
  tutorialAuto.addEventListener('click', () => {
    state.tutorialAuto = !state.tutorialAuto
    state.tutorialTimer = 0
    tutorialAuto.textContent = state.tutorialAuto ? '⏸ Auto' : '▶ Auto'
  })
}

if (gotoTriple) {
  gotoTriple.addEventListener('click', () => {
    state.tutorialAuto = false
    state.forceTripleView = true
    state.forceCriticalView = false
    state.guideActive = false
    state.targetTemp = TRIPLE_K
    state.targetPressureMmHg = TRIPLE_MMHG
    state.temp = TRIPLE_K
    setPressureState(TRIPLE_MMHG)
    state.tutorialTimer = 0
    if (tutorialAuto) tutorialAuto.textContent = '▶ Auto'
    syncAllUI()
  })
}

if (gotoCritical) {
  gotoCritical.addEventListener('click', () => {
    state.tutorialAuto = false
    state.forceTripleView = false
    state.forceCriticalView = true
    state.guideActive = false
    state.targetTemp = CRITICAL_K
    state.targetPressureMmHg = atmToMmHg(CRITICAL_ATM)
    state.temp = CRITICAL_K
    setPressureState(atmToMmHg(CRITICAL_ATM))
    state.tutorialTimer = 0
    if (tutorialAuto) tutorialAuto.textContent = '▶ Auto'
    syncAllUI()
  })
}


if (canvas) {
  canvas.addEventListener('pointerdown', startThermoPointer)
  canvas.addEventListener('pointermove', moveThermoPointer)
  canvas.addEventListener('pointerup', endThermoPointer)
  canvas.addEventListener('pointercancel', endThermoPointer)
}

document.addEventListener('keydown', e => {
  const tag = (document.activeElement && document.activeElement.tagName) ? document.activeElement.tagName.toLowerCase() : ''
  if (tag === 'input' || tag === 'select' || tag === 'textarea') return
  if (e.key === 'ArrowRight') {
    e.preventDefault()
    applyTutorialStep(state.tutorialStep + 1, false)
  } else if (e.key === 'ArrowLeft') {
    e.preventDefault()
    applyTutorialStep(state.tutorialStep - 1, false)
  }
})

window.addEventListener('resize', resize)

if (sampleSelect) populateSamples()
resize()
applyPressure(atmToMmHg(1))
applyTutorialStep(0, true)
requestAnimationFrame(tick)
